$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  Write-Output '=== QUERY LICENSE LIST via TCP 756 ==='
  function Send-LicReq($port, $body) {
    try {
      $client = New-Object System.Net.Sockets.TcpClient('127.0.0.1', $port)
      $stream = $client.GetStream()
      $data = [System.Text.Encoding]::UTF8.GetBytes($body)
      $stream.Write($data, 0, $data.Length)
      Start-Sleep -Milliseconds 800
      $buf = New-Object byte[] 65536
      $read = $stream.Read($buf, 0, $buf.Length)
      $client.Close()
      return [System.Text.Encoding]::UTF8.GetString($buf, 0, $read)
    } catch { return $_.Exception.Message }
  }

  # try common JSON-RPC style payloads used by ATOL LM
  $payloads = @(
    '{"method":"getLicenseList","parameters":{}}',
    '{"method":"getServiceInfo","parameters":{}}',
    '{"method":"getLicenseInfo","parameters":{"number":"AW1W2-D19B7-6TBPA-9MC6Q"}}'
  )
  foreach ($p in $payloads) {
    Write-Output ("--- 756: $p ---")
    Send-LicReq 756 $p
    Write-Output ''
    Write-Output ("--- 755: $p ---")
    Send-LicReq 755 $p
    Write-Output ''
  }

  Write-Output '=== CONTEXT AROUND NOT ACTIVATED ==='
  Select-String -Path 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log' -Pattern 'AW1W2|не актив|активир|Licenses updated|error' -Context 2,2 |
    Select-Object -Last 30 |
    ForEach-Object {
      if ($_.Context.PreContext) { $_.Context.PreContext | ForEach-Object { "  $_" } }
      ">$($_.Line)"
      if ($_.Context.PostContext) { $_.Context.PostContext | ForEach-Object { "  $_" } }
      '----'
    }

  Write-Output '=== FRONTOL CURRENT STATUS ==='
  Get-Service frontol-mu,AtolLicSvc | Format-Table Name,Status -AutoSize | Out-String
  Get-Process frontol-mu,AtolLicSvcStart -ErrorAction SilentlyContinue | Format-Table Id,ProcessName,StartTime -AutoSize | Out-String

  Write-Output '=== LAST START BLOCK IN FRONTOL LOG ==='
  Select-String -Path 'C:\ProgramData\ATOL\frontol-mu\log.txt' -Pattern 'Frontol Mark Unit|auth_remote|Подходящая|there is no license|license\] start' |
    Select-Object -Last 20 |
    ForEach-Object { $_.Line }
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  function Read-SharedTail($path, $tail=120) {
    $fs = [System.IO.File]::Open($path, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
    try {
      $sr = New-Object System.IO.StreamReader($fs, [System.Text.Encoding]::GetEncoding(1251), $true)
      $all = $sr.ReadToEnd()
      $sr.Close()
      return ($all -split "`r?`n") | Select-Object -Last $tail
    } finally { $fs.Close() }
  }
  function Read-SharedSearch($path, $pattern, $take=40) {
    $fs = [System.IO.File]::Open($path, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
    try {
      $sr = New-Object System.IO.StreamReader($fs, [System.Text.Encoding]::GetEncoding(1251), $true)
      $all = $sr.ReadToEnd()
      $sr.Close()
      return ($all -split "`r?`n") | Where-Object { $_ -match $pattern } | Select-Object -Last $take
    } finally { $fs.Close() }
  }

  Write-Output '=== AtolLicSvcEx: AW1W2 / activation ==='
  Read-SharedSearch 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log' 'AW1W2|актив|Active|Licenses updated|getLicenseList|errorCode|product' 50

  Write-Output "`n=== Frontol MU license lines ==="
  Read-SharedSearch 'C:\ProgramData\ATOL\frontol-mu\log.txt' 'license|auth_remote|Подходящая|there is no license|Frontol Mark Unit v' 30

  Write-Output "`n=== Frontol MU last 30 lines ==="
  Read-SharedTail 'C:\ProgramData\ATOL\frontol-mu\log.txt' 30

  Write-Output "`n=== AtolLicSvc.log last 40 ==="
  Read-SharedTail 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.log' 40
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  function Read-Shared($path) {
    $fs = [System.IO.File]::Open($path, 'Open', 'Read', 'ReadWrite')
    try {
      $sr = New-Object System.IO.StreamReader($fs, [System.Text.Encoding]::GetEncoding(1251), $true)
      $t = $sr.ReadToEnd(); $sr.Close(); return $t
    } finally { $fs.Close() }
  }

  Write-Output '=== CONTEXT AROUND AW1W2 15:28-15:45 ==='
  $ex = Read-Shared 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log'
  $lines = $ex -split "`r?`n"
  for ($i=0; $i -lt $lines.Count; $i++) {
    if ($lines[$i] -match '2026-07-21 15:2[89]|2026-07-21 15:3[0-5]|AW1W2|не актив|активир|activate|product|FMU|MARK|Mark') {
      # print nearby block for license operations
    }
  }
  # extract window 15:28:00 - 15:45:00
  $start = ($lines | Select-String -Pattern '2026-07-21 15:28:' | Select-Object -First 1).LineNumber
  if ($start) {
    $slice = $lines[([Math]::Max(0,$start-5))..([Math]::Min($lines.Count-1, $start+200))]
    $slice | Select-Object -First 220
  }

  Write-Output "`n=== STR / STATUS FILES ==="
  Get-ChildItem 'C:\ProgramData\ATOL\AtolLicSvc\*.str','C:\ProgramData\ATOL\AtolLicSvc\*.dat','C:\ProgramData\ATOL\LicenseManager\*' -ErrorAction SilentlyContinue |
    Where-Object { -not $_.PSIsContainer } |
    Select-Object FullName,Length,LastWriteTime | Format-Table -AutoSize | Out-String

  Write-Output '=== RegInfo.dat printable ==='
  $reg = [System.IO.File]::ReadAllBytes('C:\ProgramData\ATOL\LicenseManager\RegInfo.dat')
  [System.Text.Encoding]::GetEncoding(1251).GetString($reg) -replace '[^\x09\x0A\x0D\x20-\x7E\u0400-\u04FF]','.'

  Write-Output "`n=== LICENSE DIR + HASH ==="
  Get-FileHash 'C:\ProgramData\ATOL\AtolLicSvc\license\AW1W2-D19B7-6TBPA-9MC6Q.lic' -Algorithm SHA256 | Format-List | Out-String

  Write-Output '=== TOOLS IN AtolLicSvc ==='
  Get-ChildItem 'C:\Program Files (x86)\ATOL\AtolLicSvc' -Recurse -Include *.exe,*.dll -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'Lic|System|Check|Activate|Console|cli' } |
    Select-Object FullName,Length | Format-Table -AutoSize | Out-String -Width 200
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  function Read-Shared($path, [Text.Encoding]$enc=$null) {
    if (-not $enc) { $enc = [Text.Encoding]::GetEncoding(1251) }
    $fs = [IO.File]::Open($path, 'Open', 'Read', 'ReadWrite')
    try { $sr = New-Object IO.StreamReader($fs, $enc, $true); $t=$sr.ReadToEnd(); $sr.Close(); return $t } finally { $fs.Close() }
  }

  Write-Output '=== PLAINTEXT LINES WITH AW1W2 / update / activate / error ==='
  $ex = Read-Shared 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log'
  ($ex -split "`r?`n") | Where-Object { $_ -match '^\d{4}-\d{2}-\d{2}' -and $_ -match 'AW1W2|update|activ|не актив|ошиб|error|All licenses|bad allocation|FMU|MARK|Mark Unit|product' } | Select-Object -Last 80

  Write-Output "`n=== AtolLicSvc.str printable ==="
  $str = Read-Shared 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.str'
  ($str -replace '[^\x09\x0A\x0D\x20-\x7E\u0400-\u04FF]', '.') | Select-Object -First 1
  # also try as xml/json
  if ($str -match '\{|\<') { 'looks structured' } else { 'mostly binary' }
  Write-Output ("str length=" + $str.Length)

  Write-Output "`n=== frontol-mu keys ==="
  Get-ChildItem 'C:\ProgramData\ATOL\frontol-mu\keys' -Recurse -ErrorAction SilentlyContinue | Select-Object FullName,Length,LastWriteTime | Format-Table -AutoSize | Out-String

  Write-Output '=== LicManager help / exe ==='
  Get-ChildItem 'C:\Program Files (x86)\ATOL\LicManager' | Select-Object Name,Length | Format-Table -AutoSize | Out-String
  & 'C:\Program Files (x86)\ATOL\LicManager\LicenseManager.exe' /? 2>&1 | Out-String
  Get-ChildItem 'C:\Program Files (x86)\ATOL\LicManager\*.exe' | ForEach-Object { Write-Output $_.Name }
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  $path = 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log'
  $fs = [IO.File]::Open($path, 'Open', 'Read', 'ReadWrite')
  try {
    $ms = New-Object IO.MemoryStream
    $fs.CopyTo($ms)
    $bytes = $ms.ToArray()
  } finally { $fs.Close() }

  $ascii = [Text.Encoding]::ASCII.GetString($bytes)
  $markers = @('AW1W2-D19B7-6TBPA - ', 'LMRequest: activate', 'Licenses updated, but same have an error', 'bad allocation')
  foreach ($m in $markers) {
    $idx = 0; $n=0
    while (($idx = $ascii.IndexOf($m, $idx)) -ge 0 -and $n -lt 3) {
      $len = [Math]::Min(180, $bytes.Length - $idx)
      $chunk = New-Object byte[] $len
      [Array]::Copy($bytes, $idx, $chunk, 0, $len)
      Write-Output ("=== $m @ $idx ===")
      Write-Output ('CP1251: ' + ([Text.Encoding]::GetEncoding(1251).GetString($chunk) -replace "`r|`n",' | '))
      Write-Output ''
      $idx += $m.Length; $n++
    }
  }

  Write-Output '=== create missing license scan dirs (empty, safe) ==='
  New-Item -ItemType Directory -Force -Path 'C:\ProgramData\ATOL\FrontolManager\licenses' | Out-Null
  New-Item -ItemType Directory -Force -Path 'C:\Program Files (x86)\ATOL\Frontol xPOS\license' | Out-Null
  'dirs ok'

  Write-Output '=== LicenseManager_con file info / strings ==='
  $con = 'C:\Program Files (x86)\ATOL\LicManager\LicenseManager_con.exe'
  Get-Item $con | Format-List Name,Length,VersionInfo
  # try common args without touching licenses
  $argsList = @('--help','-help','/help','list','status','getLicenseList','-list')
  foreach ($a in $argsList) {
    Write-Output "--- arg: $a ---"
    $p = Start-Process -FilePath $con -ArgumentList $a -Wait -PassThru -NoNewWindow -RedirectStandardOutput "$env:TEMP\lm_out.txt" -RedirectStandardError "$env:TEMP\lm_err.txt"
    Write-Output ("exit=" + $p.ExitCode)
    if (Test-Path "$env:TEMP\lm_out.txt") { Get-Content "$env:TEMP\lm_out.txt" -ErrorAction SilentlyContinue }
    if (Test-Path "$env:TEMP\lm_err.txt") { Get-Content "$env:TEMP\lm_err.txt" -ErrorAction SilentlyContinue }
  }
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  function Read-SharedBytes($path) {
    $fs = [IO.File]::Open($path,'Open','Read','ReadWrite')
    try { $ms=New-Object IO.MemoryStream; $fs.CopyTo($ms); return $ms.ToArray() } finally { $fs.Close() }
  }
  function Read-SharedText($path, $enc) {
    $fs = [IO.File]::Open($path,'Open','Read','ReadWrite')
    try { $sr=New-Object IO.StreamReader($fs,$enc,$true); $t=$sr.ReadToEnd(); $sr.Close(); return $t } finally { $fs.Close() }
  }

  Write-Output '=== CURRENT PC ==='
  $cs = Get-CimInstance Win32_ComputerSystem
  $csp = Get-CimInstance Win32_ComputerSystemProduct
  $bios = Get-CimInstance Win32_BIOS
  $bb = Get-CimInstance Win32_BaseBoard
  $cpu = Get-CimInstance Win32_Processor | Select-Object -First 1
  $os = Get-CimInstance Win32_OperatingSystem
  [pscustomobject]@{
    Hostname=$env:COMPUTERNAME
    Domain=$cs.Domain
    Manufacturer=$cs.Manufacturer
    Model=$cs.Model
    UUID=$csp.UUID
    BiosSerial=$bios.SerialNumber
    BoardSerial=$bb.SerialNumber
    BoardProduct=$bb.Product
    CPU=$cpu.Name
    OS=$os.Caption
  } | Format-List | Out-String

  Write-Output '=== devicekey.dat hex ==='
  if (Test-Path 'C:\ProgramData\ATOL\devicekey.dat') {
    $dk = [IO.File]::ReadAllBytes('C:\ProgramData\ATOL\devicekey.dat')
    'len=' + $dk.Length + ' hex=' + (($dk | ForEach-Object { $_.ToString('X2') }) -join ' ')
  }

  Write-Output "`n=== SEARCH LOG FOR hardware / HWID / fingerprint / состав / ID ==="
  $bytes = Read-SharedBytes 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log'
  $ascii = [Text.Encoding]::ASCII.GetString($bytes)
  $utf8 = [Text.Encoding]::UTF8.GetString($bytes)
  $cp866 = [Text.Encoding]::GetEncoding(866).GetString($bytes)

  $patterns = @(
    'состава оборудования','оборудован','hardware','Hardware','HWID','hwid','fingerprint','DeviceID','deviceId','computerId','systemId','UUID','Machine','board','Serial'
  )
  foreach ($p in $patterns) {
    $hits = [regex]::Matches($cp866, ".{0,40}$([regex]::Escape($p)).{0,80}")
    if ($hits.Count -gt 0) {
      Write-Output ("-- CP866 hits for $p : " + [Math]::Min(5,$hits.Count))
      $hits | Select-Object -First 5 | ForEach-Object { $_.Value -replace "`r|`n",' ' }
    }
  }

  # extract lines containing Критичное
  Write-Output "`n=== ALL 'Критичное' LINES WITH TIMESTAMP ==="
  $lines = $cp866 -split "`r?`n"
  for ($i=0; $i -lt $lines.Count; $i++) {
    if ($lines[$i] -match 'Критичное|не активирована|AW1W2') {
      # print previous non-encrypted timestamp line if current has timestamp
      $start = [Math]::Max(0,$i-3)
      for ($j=$start; $j -le $i; $j++) {
        if ($lines[$j] -match '^\d{4}-\d{2}-\d{2}' -or $lines[$j] -match 'Критичное|не активирована|AW1W2') {
          $lines[$j]
        }
      }
      '----'
    }
  }
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  function Read-SharedBytes($path) {
    $fs=[IO.File]::Open($path,'Open','Read','ReadWrite'); try{$ms=New-Object IO.MemoryStream;$fs.CopyTo($ms);$ms.ToArray()}finally{$fs.Close()}
  }

  # Run SystemChecker if it dumps HWID
  Write-Output '=== SystemChecker ==='
  $sc = 'C:\Program Files (x86)\ATOL\AtolLicSvc\2.17.5.4063\SystemChecker.exe'
  if (Test-Path $sc) {
    $p = Start-Process -FilePath $sc -Wait -PassThru -NoNewWindow -RedirectStandardOutput "$env:TEMP\sc_out.txt" -RedirectStandardError "$env:TEMP\sc_err.txt"
    "exit=$($p.ExitCode)"
    Get-Content "$env:TEMP\sc_out.txt","$env:TEMP\sc_err.txt" -ErrorAction SilentlyContinue
  }

  Write-Output "`n=== SEARCH files for hardware keys / old hostnames ==="
  Get-ChildItem 'C:\ProgramData\ATOL' -Recurse -File -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'hardware|hwid|device|reginfo|key|fingerprint|system' -or $_.Extension -in '.str','.dat','.xml','.json','.ini','.log' } |
    Where-Object { $_.Length -lt 5MB -and $_.FullName -notmatch 'AtolLicSvcEx|frontol-mu\\log|Cache|Drivers' } |
    Select-Object FullName,Length,LastWriteTime |
    Sort-Object LastWriteTime -Descending |
    Select-Object -First 40 |
    Format-Table -AutoSize | Out-String -Width 200

  Write-Output '=== Grep plaintext hostnames / MAC / UUID in small ATOL files ==='
  $files = @(
    'C:\ProgramData\ATOL\LicenseManager\RegInfo.dat',
    'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.str',
    'C:\ProgramData\ATOL\AtolLicSvc\AtolMsgSvc.str',
    'C:\ProgramData\ATOL\devicekey.dat',
    'C:\ProgramData\ATOL\installer.cfg'
  )
  Get-ChildItem 'C:\ProgramData\ATOL\AtolLicSvc' -File | ForEach-Object { $files += $_.FullName }
  foreach ($f in ($files | Select-Object -Unique)) {
    if (-not (Test-Path $f)) { continue }
    try {
      $b = if ($f -match 'Ex\.log|frontol-mu') { $null } else { [IO.File]::ReadAllBytes($f) }
      if (-not $b) {
        $b = Read-SharedBytes $f
      }
      $t866 = [Text.Encoding]::GetEncoding(866).GetString($b)
      $t8 = [Text.Encoding]::UTF8.GetString($b)
      $tA = [Text.Encoding]::ASCII.GetString($b)
      $combined = $t866 + "`n" + $t8 + "`n" + $tA
      $found = [regex]::Matches($combined, '(DESKTOP-[A-Z0-9]+|UUID[=: ]*[0-9A-Fa-f-]{36}|([0-9A-Fa-f]{2}[:-]){5}[0-9A-Fa-f]{2}|0D2C81C6|[0-9A-F]{8}|hardwareKey|HardwareKey|compName|computerName) ')
      # simpler extractions
      $hosts = [regex]::Matches($combined, 'DESKTOP-[A-Z0-9]{4,}') | ForEach-Object { $_.Value } | Select-Object -Unique
      $uuids = [regex]::Matches($combined, '[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}') | ForEach-Object { $_.Value } | Select-Object -Unique
      $macs = [regex]::Matches($combined, '([0-9A-Fa-f]{2}[:-]){5}[0-9A-Fa-f]{2}') | ForEach-Object { $_.Value } | Select-Object -Unique
      if ($hosts -or $uuids -or $macs -or $combined -match '0D2C81C6') {
        Write-Output ("FILE: $f")
        if ($hosts) { "hosts: $($hosts -join ', ')" }
        if ($uuids) { "uuids: $($uuids -join ', ')" }
        if ($macs) { "macs: $($macs -join ', ')" }
        if ($combined -match '0D2C81C6') { 'contains current devicekey 0D2C81C6' }
      }
    } catch {}
  }

  Write-Output "`n=== Network adapters MAC (current) ==="
  Get-CimInstance Win32_NetworkAdapterConfiguration | Where-Object { $_.MACAddress } |
    Select-Object Description,MACAddress,IPAddress | Format-Table -AutoSize | Out-String

  Write-Output '=== Volume serials ==='
  Get-CimInstance Win32_LogicalDisk | Select-Object DeviceID,VolumeSerialNumber,Size | Format-Table -AutoSize | Out-String
}

# try a few common local account patterns against 1C host
$passwords = @('usr1cv8','1111','1','Admin','admin')
$users = @('.\usr1cv8','usr1cv8','.\Administrator','Administrator')
foreach ($u in $users) {
  foreach ($p in $passwords) {
    $sec = ConvertTo-SecureString $p -AsPlainText -Force
    $cred = New-Object System.Management.Automation.PSCredential($u, $sec)
    try {
      $r = Invoke-Command -ComputerName 26.143.136.109 -Credential $cred -Authentication Negotiate -ScriptBlock { "$env:COMPUTERNAME|$env:USERNAME" } -ErrorAction Stop
      Write-Output "OK user=$u pass=$p => $r"
      break
    } catch {
      $msg = $_.Exception.Message
      if ($msg -match 'Access is denied|отказано|AccessDenied') { Write-Output "DENY user=$u pass=$p" }
      else { Write-Output "FAIL user=$u pass=$p :: $($msg.Substring(0,[Math]::Min(120,$msg.Length)))" }
    }
  }
}

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.143.136.109 -Credential $cred -Authentication Negotiate -ScriptBlock {
  Write-Output '=== HOST / 1C PROCESSES ==='
  hostname
  Get-Process | Where-Object { $_.ProcessName -match '1cv8|ragent|rmngr|rphost|rac' } | Select-Object Id,ProcessName,Path | Format-Table -AutoSize | Out-String -Width 180

