    $o=([int[]][char[]]$_.Name) -join ','
    $o.StartsWith('1054,1092,1083,1072,1081,1085,1054,1073,1086,1088,1091,1076,1086,1074,1072,1085,1080,1077,1040,1090,1086,1083,1050,1050,1052,1042')
