Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  Write-Output '=== LICENSE NOW ==='
  Get-Service AtolLicSvc,frontol-mu,srvFrontol -EA SilentlyContinue | Format-Table Name,Status
  Get-ChildItem 'C:\ProgramData\ATOL\AtolLicSvc\license' -EA SilentlyContinue | Format-Table Name,Length,LastWriteTime
  Get-Content 'C:\ProgramData\ATOL\AtolLicSvc\logs\*.log' -Tail 30 -EA SilentlyContinue
  # recent MU log about license
  Select-String -Path 'C:\ProgramData\ATOL\frontol-mu\log.txt' -Pattern 'license|License|lic' -EA SilentlyContinue | Select-Object -Last 15 | ForEach-Object { $_.Line }

  # Read backoffice settings from sqlite via powershell + LoadFile System.Data.SQLite
  $dll = Get-ChildItem 'C:\Program Files (x86)\ATOL' -Recurse -Filter 'System.Data.SQLite.dll' -EA SilentlyContinue | Select-Object -First 1 -ExpandProperty FullName
  "sqlite_dll=$dll"
  if ($dll) {
    Add-Type -Path $dll
    $conn = New-Object System.Data.SQLite.SQLiteConnection('Data Source=C:\ProgramData\ATOL\frontol-mu\database.db;Version=3;Read Only=True;')
    $conn.Open()
    $cmd = $conn.CreateCommand()
    $cmd.CommandText = "SELECT name FROM sqlite_master WHERE type='table'"
    $r=$cmd.ExecuteReader(); $tables=@(); while($r.Read()){ $tables += $r.GetString(0) }; $r.Close()
    "TABLES=$($tables -join ',')"
    foreach ($t in $tables) {
      if ($t -match 'set|path|back|import|config|shop') {
        $cmd.CommandText = "SELECT * FROM [$t] LIMIT 30"
        try {
          $r=$cmd.ExecuteReader()
          "=== $t ==="
          while ($r.Read()) {
            $vals=@(); for($i=0;$i -lt $r.FieldCount;$i++){ $vals += "$($r.GetName($i))=$($r.GetValue($i))" }
            $vals -join ' | '
          }
          $r.Close()
        } catch { "err $t $_" }
      }
    }
    $conn.Close()
  }
}

