    $par = Prop $du (U @(0x041F,0x0430,0x0440,0x0430,0x043C,0x0435,0x0442,0x0440,0x044B))
    $fmt = [int](Prop $par (U @(0x0424,0x043E,0x0440,0x043C,0x0430,0x0442,0x041E,0x0431,0x043C,0x0435,0x043D,0x0430)))
    $remoteGoods = [string](Prop $par (U @(0x0411,0x0430,0x0437,0x0430,0x0422,0x043E,0x0432,0x0430,0x0440,0x043E,0x0432)))
    $remoteFlag = [string](Prop $par (U @(0x0424,0x043B,0x0430,0x0433,0x0412,0x044B,0x0433,0x0440,0x0443,0x0437,0x043A,0x0438)))
    L "fmt=$fmt goods=$remoteGoods flag=$remoteFlag"

    # Taxes from params structure (НомерНалога*)
