            L ("wrote local size=" + (Get-Item $localGoods).Length)
        } catch {
            L "formatter2 FAIL: $($_.Exception.Message)"
        }
    }

    if (Test-Path $localGoods) {
        [IO.File]::WriteAllText($localFlag, ' ', [Text.Encoding]::GetEncoding(1251))
