  for ($i=0; $i -le $bytes.Length-$needle2.Length; $i++) {
    $ok=$true
    for ($j=0; $j -lt $needle2.Length; $j++) { if ($bytes[$i+$j] -ne $needle2[$j]) { $ok=$false; break } }
    if ($ok) { $positions2 += $i; if ($positions2.Count -ge 20) { break } }
  }
  [void]$sb.AppendLine("UTF16 positions of ЗаполнитьПрайсЛистККМ: $($positions2 -join ',')")

